78rem}.listing-empty{display:flex;align-items:center;gap:18px;margin-top:24px;padding:22px;border:1px dashed var(--bos-line);border-radius:16px}.listing-empty>span{font-size:2rem}.listing-empty h3,.listing-empty p{margin:3px 0}.listing-empty p{color:var(--bos-muted)}.listing-empty .bos-btn{margin-left:auto}.product-dialog{width:min(560px,calc(100% - 28px));padding:30px;border:1px solid rgba(255,255,255,.2);border-radius:24px;background:#11142f;color:white}.product-dialog::backdrop{background:rgba(2,4,13,.78);backdrop-filter:blur(8px)}.product-dialog h2{font-size:2.2rem;margin:.35rem 0}.product-dialog p,.dialog-notice{color:#b5bad2;line-height:1.6}.product-dialog>strong{display:block;margin:17px 0;font-size:1.4rem}.dialog-notice{padding:13px;border:1px solid rgba(255,255,255,.1);border-radius:12px;background:rgba(255,255,255,.04);font-size:.8rem}.dialog-close{float:right;border:0;background:none;color:white;font-size:2rem;cursor:pointer}.market-page a:focus-visible,.market-page button:focus-visible,.market-page input:focus-visible,.market-page select:focus-visible{outline:3px solid #ff83bc;outline-offset:3px}@keyframes marketFloat{50%{transform:translateY(-11px) rotate(5deg)}}
