<style>.listing-card strong:empty::after{content:"Free"}</style>
<script>
(()=>{const form=document.getElementById('marketSearch'),query=document.getElementById('marketQuery'),select=document.getElementById('marketCategory'),sort=document.getElementById('marketSort'),grid=document.getElementById('productGrid'),cards=[...grid.querySelectorAll('.product-card')],filters=[...document.querySelectorAll('[data-market-filter]')],count=document.getElementById('productCount'),empty=document.getElementById('productEmpty');let category='all';function update(){const term=query.value.trim().toLowerCase(),selected=select.value==='all'?category:select.value;let visible=0;cards.forEach(card=>{const matchCategory=selected==='all'||card.dataset.category===selected,matchText=!term||card.dataset.search.includes(term);card.hidden=!(matchCategory&&matchText);if(!card.hidden)visible++});count.textContent=visible+' Canvas-ready categor'+(visible===1?'y':'ies');empty.hidden=visible!==0}function sortCards(){const mode=sort.value;cards.sort((a,b)=>mode==='low'?Number(a.dataset.price)-Number(b.dataset.price):mode==='name'?a.dataset.name.localeCompare(b.dataset.name):0).forEach(card=>grid.append(card))}form.addEventListener('submit',event=>{event.preventDefault();update();document.getElementById('shop').scrollIntoView({behavior:'smooth'})});query.addEventListener('input',update);select.addEventListener('change',update);sort.addEventListener('change',()=>{sortCards();update()});filters.forEach(button=>button.addEventListener('click',()=>{category=button.dataset.marketFilter;select.value='all';filters.forEach(item=>item.classList.toggle('active',item===button));update()}));document.querySelectorAll('.watch-button').forEach(button=>button.addEventListener('click',()=>{button.classList.toggle('saved');button.textContent=button.classList.contains('saved')?'♥':'♡';button.setAttribute('aria-pressed',button.classList.contains('saved')?'true':'false')}));const dialog=document.getElementById('productDialog'),title=document.getElementById('dialogTitle'),dialogCategory=document.getElementById('dialogCategory'),copy=document.getElementById('dialogCopy'),price=document.getElementById('dialogPrice'),create=document.getElementById('dialogCreate');document.querySelectorAll('.quick-view').forEach(button=>button.addEventListener('click',()=>{title.textContent=button.dataset.product;dialogCategory.textContent=button.dataset.category+' · Beyond Canvas';copy.textContent=button.dataset.copy;price.textContent=button.dataset.price;create.href=button.dataset.href;dialog.showModal()}));dialog.querySelectorAll('.dialog-close,.dialog-close-action').forEach(button=>button.addEventListener('click',()=>dialog.close()));dialog.addEventListener('click',event=>{if(event.target===dialog)dialog.close()})})();
</script>
